files.notice.nz.liquid:
{% component block %}

{% props {
  message: string.setting({ label: "Message", default: "Heads up!" }),
  tone: string.enum("info", "success", "warning").setting({
    label: "Tone",
    default: "info",
  }),
} %}

<div class="nazare-notice nazare-notice--{{ props.tone }}">
  {{ props.message }}
</div>

{% stylesheet %}
.nazare-notice {
  padding: 0.75rem 1rem;
  border-radius: 0.5rem;
}
.nazare-notice--info { background: rgb(219 234 254); }
.nazare-notice--success { background: rgb(220 252 231); }
.nazare-notice--warning { background: rgb(254 249 195); }
{% endstylesheet %}
